protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // HasIndex throws at startup in EF Core 9 Cosmos — manage indexing
    // via the container's indexing policy (Azure Portal / Bicep / Terraform).

    modelBuilder.Entity<Product>().ToContainer("Products");

    // Preserve EF Core 8 discriminator property name ("Discriminator")
    // so existing documents and direct SQL queries remain compatible.
    // EF Core 9 defaults to "$type".
    modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");

    // Preserve EF Core 8 compound id format ("Product|123") so FindAsync
    // and point-reads work against the 500K existing documents.
    // EF Core 9 defaults to key-only ids ("123").
    modelBuilder.Entity<Product>().HasRootDiscriminatorInJsonId(true);
}

